inline int maximum(int a, int b, int c) {
    int k = (a <= b) ? b : a;
    return (k <= c) ? c : k;
}

__kernel void nw_kernel1(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* temp,
                         __local int* ref,
                         int cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    (void)output_itemsets;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    const int bx = get_group_id(0);
    const int tx = get_local_id(0);

    const int b_index_x = bx;
    const int b_index_y = blk - 1 - bx;

    const int index    = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    const int index_n  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + 1;
    const int index_w  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    const int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    if (tx == 0) {
        temp[0 * (BLOCK_SIZE + 1) + 0] = input_itemsets[index_nw];
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref[ty * BLOCK_SIZE + tx] = reference[index + cols * ty];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[(tx + 1) * (BLOCK_SIZE + 1) + 0] = input_itemsets[index_w + cols * tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[0 * (BLOCK_SIZE + 1) + (tx + 1)] = input_itemsets[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            const int t_index_x = tx + 1;
            const int t_index_y = m - tx + 1;

            const int v_nw = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            const int v_w  = temp[t_index_y * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            const int v_n  = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + t_index_x];
            const int v_r  = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] =
                maximum(v_nw + v_r, v_w - penalty, v_n - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            const int t_index_x = tx + BLOCK_SIZE - m;
            const int t_index_y = BLOCK_SIZE - tx;

            const int v_nw = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            const int v_w  = temp[t_index_y * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            const int v_n  = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + t_index_x];
            const int v_r  = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] =
                maximum(v_nw + v_r, v_w - penalty, v_n - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        input_itemsets[index + ty * cols] = temp[(ty + 1) * (BLOCK_SIZE + 1) + (tx + 1)];
    }
}

